(function(){const o=document.createElement("link").relList;if(o&&o.supports&&o.supports("modulepreload"))return;for(const e of document.querySelectorAll('link[rel="modulepreload"]'))i(e);new MutationObserver(e=>{for(const t of e)if(t.type==="childList")for(const a of t.addedNodes)a.tagName==="LINK"&&a.rel==="modulepreload"&&i(a)}).observe(document,{childList:!0,subtree:!0});function r(e){const t={};return e.integrity&&(t.integrity=e.integrity),e.referrerPolicy&&(t.referrerPolicy=e.referrerPolicy),e.crossOrigin==="use-credentials"?t.credentials="include":e.crossOrigin==="anonymous"?t.credentials="omit":t.credentials="same-origin",t}function i(e){if(e.ep)return;e.ep=!0;const t=r(e);fetch(e.href,t)}})();const s={siteTitle:"Aayush Jain",email:"aayush2@stanford.edu",year:"2026",introShort:"a/j",introFull:"Aayush Jain",headline:"Building interfaces for new forms of computation. Making the most complex tasks accessible to everyday people.",leftBio:[{text:"Hi, I am Aayush, a creative technologist. I build products that democratize access to personalized expertise through intelligent interfaces. Currently an undergraduate student at "},{text:"Stanford,",bold:!0,url:"https://www.stanford.edu/"},{text:" I've previously made stops at "},{text:"Arcade,",bold:!0,url:"https://wwd.com/business-news/technology/arcade-ai-maia-custom-design-platform-1238339735/"},{text:" "},{text:"Glean,",bold:!0,url:"https://www.glean.com/connectors"},{text:" "},{text:"Apple,",bold:!0,url:"https://ads.apple.com/app-store"},{text:" "},{text:"AutoZone,",bold:!0,url:"https://www.autozone.com/"},{text:" "},{text:"St. Jude Children's Research Hospital,",bold:!0,url:"https://www.stjude.org/research/labs/yu-lab.html"},{text:" and the "},{text:"University of Memphis.",bold:!0,url:"https://www.memphis.edu/"}],rightBio:"My work spans zero-to-one product development, user research, and cross-functional execution. I care most about the early stages: finding the insight that changes how a team thinks about the problem, then moving fast enough to learn before assumptions calcify. Some of the products I've built and shipped can be found below.",links:[{label:"Email",url:"mailto:aayush2@stanford.edu"},{label:"CV",url:"/Aayush_Jain_Resume.pdf"},{label:"LinkedIn",url:"https://www.linkedin.com/in/aajain2/"}],sectionHeading:"Projects and roles I'm currently working on",projects:[{title:"Foresight",categories:"UX and QA Testing Automation, Browser Use Agents",description:"Software development has never moved faster. Understanding how users experience that software has not kept up. I built Foresight with some of my closest friends — three random roommates drawn into the same Stanford triple junior year who never expected much from it — to close that gap by deploying AI agents that navigate live product interfaces like real users, clicking, scrolling, and completing workflows autonomously to surface usability failures and regressions before they reach production. We started with a broader vision around synthetic user simulation, learned quickly that teams wanted automation of repetitive testing work rather than a replacement for real research, and rebuilt the entire system from scratch around that insight. Early pilots converted into paying customers.",link:null},{title:"Aora",categories:"Generative AI, Consumer Products, Human-Computer Interaction",description:"The fragrance industry sells catalogs. People want signatures. We built Aora to explore whether AI could translate subjective identity signals — memories, moods, places, aesthetics — into structured fragrance compositions of top, middle, and base notes. We validated the system inside a real custom perfume store, mixing AI-generated formulations into physical scents. In one case, a customer's AI-generated formula produced a perfume closer to what they had imagined than the one they mixed by hand.",link:null},{title:"Trabit",categories:"Human-Computer Interaction, Social Computing, Mobile Development",description:"Habit tracking fails in isolation, not from lack of desire, but lack of witness. We designed Trabit around the insight that consistency is easier to maintain when it is visible to people you care about. Users pick one habit, post a daily photo proving they did it, and face a “Yesterday's Report” naming anyone who slipped. We piloted with 16 Stanford students across two close friend groups, achieved 75% daily posting rates, and watched the app spread through word of mouth beyond the initial cohorts before the pilot had even ended.",link:{label:"Read more at GitHub",url:"#"}},{title:"Phytochemicals in Chemoprevention: A Cost-Effective Complementary Approach",categories:"Cancer Biology, Biochemistry, Translational Medicine",description:"Conventional chemotherapy kills indiscriminately, targeting tumor cells but producing dose-limiting side effects that can halt treatment entirely. I saw dietary phytochemicals as an underexplored answer: compounds found in everyday foods that exert cytotoxic effects on cancerous cells while protecting healthy tissue from chemotherapy-induced damage. This review examines five of them — quercetin, isoflavones, curcumin, catechins, and hesperidin — across their mechanisms, clinical evidence, and bioavailability. Published in the Journal of Cancer.",link:{label:"Read the paper",url:"#"}},{title:"Fine Art",categories:"Charcoal, Mixed Media, Installations",description:"Exhibited at Pratt Manhattan Gallery, Memphis International Airport, and Brooks Museum of Art, and sold to Gus's Fried Chicken and private buyers.",link:{label:"See selected works",url:"fine-art.html"}}],contact:{backLabel:"← Back",note:"I'm always open for interesting opportunities. Feel free to reach out for collaboration, commission, or just a coffee chat.",imageAlt:"Horse"}};export{s as C};
